const body = $input.first().json.body || $input.first().json;
const payload = body.payload || body;

const { referralType, referringProvider, specialtyNeeded, urgency, notes } = payload;

if (!referralType || !specialtyNeeded) {
  return [{ json: { success: false, error: 'Missing referralType or specialtyNeeded' } }];
}

const referral = {
  referralId: `REF-${Date.now()}`,
  type: referralType,
  referringProvider: referringProvider || 'Unknown',
  specialtyNeeded,
  urgency: urgency || 'routine',
  notes: notes || '',
  status: 'pending',
  createdAt: new Date().toISOString(),
  estimatedResponseDays: urgency === 'urgent' ? 1 : urgency === 'semi-urgent' ? 3 : 7,
  source: 'n8n-referral-management'
};

return [{ json: { success: true, referral } }];
